import outlines
from outlines.prompts import register_filter, unregister_filter

@outlines.prompt
def basic(text):
    '''{{ text }}'''
print(basic('hello'))

@outlines.prompt(filters={'reverse': lambda s: s[::-1]})
def reverse_prompt(text):
    '''{{ text | reverse }}'''
print(reverse_prompt('hello'))

register_filter('shout', lambda s: s.upper())
@outlines.prompt
def shout_prompt(text):
    '''{{ text | shout }}'''
print(shout_prompt('hi'))
unregister_filter('shout')
